        distance = calculate_distance(truck_pos, customer_pos)
        time_to_arrive = distance / truck_speed + current_time
        if time_to_arrive > customer_time_window[1]:
            return -1
        waiting_time = max(0, customer_time_window[0] - time_to_arrive)
        return 1 / (distance + waiting_time + 0.1*time_to_arrive)  # New parameter setting

    best_node = None
    best_score = float('-inf')
    for i, customer_pos in enumerate(unvisited_customers):
